script:
try:
    frappe.log_error(title="Salary Slip Script Triggered", message="Processing Salary Slip: " + doc.name)

    deduction_priority = [
        "COTU", "KPAWU", "Canteen Deduction", "Sacco Loan",
        "Sacco Emergency Loan", "Sacco Deposits", "Meko Gas",
        "Benevolent Deduction", "Laptops", "Okolea Cash", "Farm Produce",
        "Solar Panel Deduction", "Payroll Recoveries"
    ]

    statutory_deductions = [
        "NSSF Tier 1",
        "NSSF Tier 2",
        "Housing Levy",
        "SHIF",
        "HELB Loan"
    ]

    priority_deductions = []

    # Gross Pay
    try:
        gross_pay_val = float(doc.gross_pay or 0)
    except:
        gross_pay_val = 0.0

    max_deductions_val = gross_pay_val * 0.6666666667
    statutory_total = 0.0
    voluntary_deductions = []
    deduction_lookup = {}

    # Collect deductions
    for ded in (doc.deductions or []):
        if not ded.do_not_include_in_total:
            deduction_lookup[ded.salary_component] = ded
            if ded.salary_component in statutory_deductions:
                try:
                    statutory_total = statutory_total + float(ded.amount or 0)
                except:
                    pass

    # Build voluntary deductions
    for comp in deduction_priority:
        if comp in deduction_lookup:
            voluntary_deductions.append(deduction_lookup[comp])
    for ded in (doc.deductions or []):
        if (not ded.do_not_include_in_total
            and ded.salary_component not in statutory_deductions
            and ded.salary_component not in deduction_priority):
            voluntary_deductions.append(ded)

    # Apply 1/3 rule
    available_budget = max_deductions_val - statutory_total
    if available_budget < 0:
        available_budget = 0.0

    remaining_budget = available_budget
    for ded in voluntary_deductions:
        try:
            amt = float(ded.amount or 0)
        except:
            amt = 0.0

        if remaining_budget >= amt:
            remaining_budget = remaining_budget - amt
        elif remaining_budget > 0:
            ded.amount = remaining_budget
            remaining_budget = 0.0
        else:
            ded.amount = 0.0

    # Final totals
    new_total_deduction = 0.0
    for d in doc.deductions:
        if not d.do_not_include_in_total:
            try:
                new_total_deduction = new_total_deduction + float(d.amount or 0)
            except:
                pass

    doc.total_deduction = round(new_total_deduction, 2)
    doc.net_pay = round(gross_pay_val - new_total_deduction, 2)
    if doc.net_pay < 0:
        doc.net_pay = 0.0
    doc.rounded_total = round(doc.net_pay, 0)

    frappe.log_error(
        title="Final 1/3 Results",
        message="Net Pay = " + str(doc.net_pay) + ", Total Deduction = " + str(new_total_deduction)
    )

except Exception as e:
    frappe.log_error(
        title="Salary Slip Server Script Error",
        message="Error in salary slip processing: " + str(e)
    )

salary_slips_json = frappe.form_dict.salary_slips

# Manual parsing: remove brackets and quotes, split by comma
# Input: '["Sal Slip/3075/00004","Sal Slip/1601/00004"]'
# Output: ['Sal Slip/3075/00004', 'Sal Slip/1601/00004']

if salary_slips_json:
    # Remove leading/trailing brackets and whitespace
    cleaned = salary_slips_json.strip()[1:-1]

    # Split by comma and clean each item
    selected_slip_names = []
    if cleaned:
        items = cleaned.split('","')
        for item in items:
            # Remove any remaining quotes
            clean_item = item.replace('"', '').replace("'", '').strip()
            if clean_item:
                selected_slip_names.append(clean_item)
else:
    selected_slip_names = []

if not selected_slip_names:
    frappe.response["message"] = {
        "status": "error",
        "error": "No salary slips provided"
    }
else:
    breaches = []
    salary_slips = frappe.get_all(
        "Salary Slip",
        filters={
            "name": ["in", selected_slip_names],
            "docstatus": ["in", [0, 1]]
        },
        fields=["name", "employee", "employee_name", "gross_pay", "net_pay", "total_deduction", "docstatus"]
    )

    for slip in salary_slips:
        gross_pay = slip.gross_pay or 0
        net_pay = slip.net_pay or 0

        if gross_pay > 0:
            threshold = (1.0 / 3.0) * gross_pay

            if net_pay < threshold:
                shortfall = threshold - net_pay

                if slip.docstatus == 1:
                    try:
                        frappe.db.set_value(
                            "Employee",
                            slip.employee,
                            "custom_deferred_deduction",
                            shortfall
                        )
                        frappe.db.commit()
                    except Exception as e:
                        frappe.log_error("Failed to update deferred deduction for " + slip.employee)

                slip_doc = frappe.get_doc("Salary Slip", slip.name)

                earnings = []
                for e in slip_doc.earnings:
                    earnings.append({
                        "component": e.salary_component,
                        "amount": e.amount or 0,
                        "abbr": e.abbr or ""
                    })

                deductions = []
                for d in slip_doc.deductions:
                    deductions.append({
                        "component": d.salary_component,
                        "amount": d.amount or 0,
                        "abbr": d.abbr or ""
                    })

                breaches.append({
                    "salary_slip": slip.name,
                    "employee": slip.employee,
                    "employee_name": slip.employee_name,
                    "gross_pay": gross_pay,
                    "total_deduction": slip.total_deduction or 0,
                    "net_pay": net_pay,
                    "threshold": threshold,
                    "shortfall": shortfall,
                    "docstatus": slip.docstatus,
                    "earnings": earnings,
                    "deductions": deductions
                })

    frappe.response["message"] = {
        "status": "success",
        "breaches": breaches,
        "all_slips": salary_slips,
        "total_checked": len(salary_slips),
        "total_breaches": len(breaches)
    }

required_employment_types = ["Annual Contract", "Seasonal", "Permanent"]

# Only run during creation, not during imports, and only if COTU is not checked
if doc.is_new() and not doc.flags.ignore_validate:
    if doc.employment_type in required_employment_types and not doc.custom_cotu:
        frappe.msgprint(
            msg="Please confirm if the COTU box is checked.",
            title="COTU Validation",
            indicator="blue"
        )

if doc.has_value_changed('workflow_state'):
    new_state = doc.workflow_state

    # When Approved or Rejected - notify owner
    if new_state in ["Approved", "Rejected"]:
        try:
            # Create system notification directly (bypass email)
            notif_log = frappe.get_doc({
                'doctype': 'Notification Log',
                'subject': f'Employee {doc.name} {new_state}',
                'for_user': doc.owner,
                'type': 'Alert',
                'document_type': 'Employee',
                'document_name': doc.name,
                'from_user': frappe.session.user
            })
            notif_log.insert(ignore_permissions=True)
            frappe.db.commit()
        except Exception as e:
            frappe.log_error(f"Notification error: {str(e)}", "Employee Notification")

    # When Pending Approval - notify Management
    elif new_state == "Pending Approval":
        try:
            mgmt_users = frappe.get_all('Has Role',
                filters={'role': 'Management_employee_creation', 'parenttype': 'User'},
                fields=['parent'])

            for user in mgmt_users:
                user_doc = frappe.get_doc('User', user.parent)
                if user_doc.enabled and user_doc.name != doc.owner:
                    notif_log = frappe.get_doc({
                        'doctype': 'Notification Log',
                        'subject': f'Employee {doc.name} Submitted for Approval',
                        'for_user': user.parent,
                        'type': 'Alert',
                        'document_type': 'Employee',
                        'document_name': doc.name,
                        'from_user': doc.owner
                    })
                    notif_log.insert(ignore_permissions=True)
            frappe.db.commit()
        except Exception as e:
            frappe.log_error(f"Notification error: {str(e)}", "Employee Notification")

# Get the payroll_entry argument from frappe.form_dict
payroll_entry_name = frappe.form_dict.payroll_entry

# Get all draft salary slips for this payroll entry
salary_slips = frappe.get_all(
    "Salary Slip",
    filters={
        "payroll_entry": payroll_entry_name,
        "docstatus": 0  # Draft only
    },
    fields=["name", "employee", "employee_name", "gross_pay", "net_pay"]
)

if not salary_slips:
    frappe.response["message"] = {"status": "no_slips", "message": "No draft salary slips found"}
else:
    violations = []

    for slip in salary_slips:
        gross_pay = slip.gross_pay or 0
        net_pay = slip.net_pay or 0

        if gross_pay > 0:
            threshold = (1.0 / 3.0) * gross_pay

            if net_pay < threshold:
                violations.append({
                    "employee": slip.employee,
                    "employee_name": slip.employee_name,
                    "salary_slip": slip.name,
                    "shortfall": threshold - net_pay
                })

    if violations:
        frappe.response["message"] = {
            "status": "violation",
            "count": len(violations),
            "total": len(salary_slips)
        }
    else:
        frappe.response["message"] = {"status": "success", "total": len(salary_slips)}

# NO IMPORTS AT ALL — works in Server Script

@frappe.whitelist()
def get_employees(advanced_filters=None):
    # 1. Parse advanced_filters (it comes as JSON string)
    if isinstance(advanced_filters, str):
        try:
            advanced_filters = frappe.parse_json(advanced_filters or "[]")
        except:
            advanced_filters = []
    else:
        advanced_filters = advanced_filters or []

    # 2. Get current user roles (no import needed)
    user_roles = [row.role for row in frappe.get_all(
        "Has Role",
        filters={"parent": frappe.session.user},
        fields=["role"]
    )]

    # 3. Change ONLY this line to your EXACT role name (case-sensitive!)
    restricted_role = "Payroll manager (non-management)"
    full_access_roles = ["Payroll Manager (Management & non_management)", "System Manager"]

    is_restricted = restricted_role in user_roles
    has_full_access = any(r in user_roles for r in full_access_roles)

    # 4. The magic — extra filter
    extra_filters = []
    if is_restricted and not has_full_access:
        extra_filters.append(["employment_type", "in", ["Permanent", "Seasonal", "Annual Contract"]])

        # Optional nice message
        frappe.publish_realtime("msgprint", {
            "message": "Showing only <b>Permanent, Seasonal, Annual Contract</b> employees (role restriction).",
            "indicator": "blue"
        })

    # 5. Call original method with our filter added
    final_filters = advanced_filters + extra_filters

    doc = frappe.new_doc("Bulk Salary Structure Assignment")
    return doc.get_employees(final_filters)
